from leann.api import SearchResult
from leann.metadata_filter import MetadataFilterEngine
from collections import defaultdict

def aggregate_search_results(
    search_results: List[SearchResult],
    group_by_field: str,
    aggregation_funcs: Optional[Dict[str, Callable]] = None
) -> Dict[str, Dict[str, Any]]:
    """Aggregate search results by a metadata field with optional statistics.

    Args:
        search_results: List of SearchResult objects to aggregate
        group_by_field: Metadata field name to group by
        aggregation_funcs: Optional dictionary mapping field_name to aggregation function.
            Example: {"score": max, "count": len}
            If None, defaults to count and average score per group

    Returns:
        Dictionary mapping group_value to aggregated statistics
        Example: {"tech": {"count": 5, "avg_score": 0.85, "max_score": 0.95}}
    """
    # Handle empty input
    if not search_results:
        return {}

    # Define default aggregation functions if none provided
    if aggregation_funcs is None:
        aggregation_funcs = {
            "count": len,
            "avg_score": lambda group: sum(r.score for r in group) / len(group) if group else 0.0,
            "max_score": lambda group: max(r.score for r in group) if group else 0.0,
            "min_score": lambda group: min(r.score for r in group) if group else 0.0
        }

    # Initialize grouping structure
    grouped_results = defaultdict(list)

    # Group results by the specified metadata field
    for result in search_results:
        # Extract metadata field value
        metadata = result.metadata or {}
        group_value = metadata.get(group_by_field)

        # Handle missing field values by assigning to 'unknown' group
        if group_value is None:
            group_value = "unknown"

        grouped_results[group_value].append(result)

    # Aggregate statistics for each group
    aggregated_data = {}

    for group_value, result_group in grouped_results.items():
        group_stats = {}

        # Apply all aggregation functions to the current group
        for field_name, agg_func in aggregation_funcs.items():
            try:
                # Apply the aggregation function to the current group
                field_result = agg_func(result_group)
                group_stats[field_name] = field_result
            except (ValueError, ZeroDivisionError):
                # Handle potential errors (empty groups, invalid operations)
                group_stats[field_name] = 0.0  # or appropriate default

        aggregated_data[group_value] = group_stats

    return aggregated_data

