from typing import List, Dict, Any
from leann.api import PassageManager, LeannSearcher
from pathlib import Path
import json
from collections import Counter, defaultdict

def get_index_statistics(
    index_path: str
) -> Dict[str, Any]:
    """Get comprehensive statistics about a LEANN index.

Args:
    index_path: Path to the LEANN index file

Returns:
    Dictionary containing:
    {
        "total_passages": total number of passages,
        "metadata_fields": list of unique metadata field names,
        "field_value_counts": dictionary of field value counts
    }

Raises:
    FileNotFoundError: If index metadata file is not found"""
    try:
        # Initialize PassageManager to load index metadata
        passage_manager = PassageManager([index_path])

        # Calculate total passages by summing passage counts from all sources
        total_passages = 0
        for source in passage_manager.passage_sources:
            total_passages += source.get("total_passages", 0)

        # Extract unique metadata field names from passage data
        metadata_fields = set()
        for passage_file in passage_manager.passage_files.values():
            with open(passage_file, 'r', encoding='utf-8') as f:
                for line in f:
                    try:
                        passage_data = json.loads(line.strip())
                        metadata = passage_data.get('metadata', {})
                        metadata_fields.update(metadata.keys())
                    except json.JSONDecodeError:
                        continue

        # Count field value occurrences
        field_value_counts = defaultdict(Counter)
        for passage_file in passage_manager.passage_files.values():
            with open(passage_file, 'r', encoding='utf-8') as f:
                for line in f:
                    try:
                        passage_data = json.loads(line.strip())
                        metadata = passage_data.get('metadata', {})
                        for field, value in metadata.items():
                            if field in metadata_fields:
                                field_value_counts[field][value] += 1
                    except json.JSONDecodeError:
                        continue

        return {
            "total_passages": total_passages,
            "metadata_fields": list(metadata_fields),
            "field_value_counts": dict(field_value_counts)
        }

    except FileNotFoundError as e:
        raise FileNotFoundError(f"Index metadata file not found: {e}")
    except Exception as e:
        raise RuntimeError(f"Error reading index statistics: {e}")

def analyze_index_coverage(index_path: str, required_fields: List[str]) -> Dict[str, Any]:
    """Analyze how well an index covers required metadata fields.

Args:
    index_path: Path to the LEANN index file
    required_fields: List of metadata field names that should be present

Returns:
    Dictionary containing:
    {
        "coverage_percentage": percentage of passages that have all required fields,
        "field_coverage": dictionary mapping field name to coverage percentage,
        "missing_fields": list of required fields not found in any passage
    }

Raises:
    FileNotFoundError: If index metadata file is not found"""
    try:
        # Initialize PassageManager to load index metadata
        passage_manager = PassageManager([index_path])

        total_passages = 0
        passages_with_all_fields = 0
        field_occurrences = defaultdict(int)
        missing_fields = []

        # Check each passage for required fields
        for passage_file in passage_manager.passage_files.values():
            with open(passage_file, 'r', encoding='utf-8') as f:
                for line in f:
                    try:
                        passage_data = json.loads(line.strip())
                        metadata = passage_data.get('metadata', {})
                        total_passages += 1

                        # Check if all required fields are present
                        has_all_fields = True
                        for field in required_fields:
                            if field not in metadata:
                                has_all_fields = False
                                break
                        if has_all_fields:
                            passages_with_all_fields += 1

                        # Track individual field occurrences
                        for field in required_fields:
                            if field in metadata:
                                field_occurrences[field] += 1
                    except json.JSONDecodeError:
                        continue

        # Calculate coverage percentages
        coverage_percentage = (passages_with_all_fields / total_passages * 100) if total_passages > 0 else 0

        field_coverage = {}
        for field in required_fields:
            field_coverage[field] = (field_occurrences[field] / total_passages * 100) if total_passages > 0 else 0

        # Identify missing fields
        missing_fields = [field for field in required_fields if field not in field_occurrences]

        return {
            "coverage_percentage": coverage_percentage,
            "field_coverage": field_coverage,
            "missing_fields": missing_fields
        }

    except FileNotFoundError as e:
        raise FileNotFoundError(f"Index metadata file not found: {e}")
    except Exception as e:
        raise RuntimeError(f"Error analyzing index coverage: {e}")
